     * @param directions The 6-character string of 'D' and 'R'.
     * @return A list of 7 integers representing the sequence of visited digits.
     */
    def calculateSequence(digits: Array[Int], directions: String): List[Int] = {
        // Initialize the 4x4 grid
        val grid = Array.ofDim[Int](4, 4)
        var k = 0
        for (i <- 0 until 4) {
            for (j <- 0 until 4) {
                grid(i)(j) = digits(k)
                k += 1
            }
        }

        // Path traversal
        var r = 0
        var c = 0
        val sequence = new scala.collection.mutable.ListBuffer[Int]()

        // Record the starting cell's value
        sequence += grid(r)(c)

        // Apply the 6 directions
